    String name;
    String email;
    String url;

    Author({
        required this.name,
        required this.email,
        required this.url,
    });

    factory Author.fromJson(Map<String, dynamic> json) => Author(
        name: json["name"],
        email: json["email"],
        url: json["url"],
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "email": email,
        "url": url,
    };
}

