class Exports {
    List<dynamic> empty;
    List<dynamic> sync;

    Exports({
        required this.empty,
        required this.sync,
    });

    factory Exports.fromJson(Map<String, dynamic> json) => Exports(
        empty: List<dynamic>.from(json["."].map((x) => x)),
        sync: List<dynamic>.from(json["./sync"].map((x) => x)),
    );

    Map<String, dynamic> toJson() => {
        ".": List<dynamic>.from(empty.map((x) => x)),
        "./sync": List<dynamic>.from(sync.map((x) => x)),
    };
}

